import{_ as t,c as o,a0 as r,o as a}from"./chunks/framework.B6JXc2q-.js";const g=JSON.parse('{"title":"Relay 术语规范","description":"","frontmatter":{},"headers":[],"relativePath":"spec/relay_terminology.md","filePath":"spec/relay_terminology.md"}'),d={name:"spec/relay_terminology.md"};function s(l,e,i,n,c,y){return a(),o("div",null,e[0]||(e[0]=[r('<h1 id="relay-术语规范" tabindex="-1">Relay 术语规范 <a class="header-anchor" href="#relay-术语规范" aria-label="Permalink to &quot;Relay 术语规范&quot;">​</a></h1><blockquote><p>版本：v1.0.9 生效日期：2026-03-21 适用范围：xiaomusic-core 全代码库与项目文档</p></blockquote><hr><h2 id="_1-术语定义" tabindex="-1">1. 术语定义 <a class="header-anchor" href="#_1-术语定义" aria-label="Permalink to &quot;1. 术语定义&quot;">​</a></h2><table tabindex="0"><thead><tr><th>正式术语</th><th>说明</th></tr></thead><tbody><tr><td><strong>relay</strong></td><td>xiaomusic 建立 relay session 并通过站内流端点（<code>/relay/stream/{sid}</code>）输出的流媒体。relay 会话有独立的生命周期与资源占用。</td></tr><tr><td><strong>proxy</strong></td><td>xiaomusic 代理请求并将响应透传，不建立持久会话。设备侧拿到的是经过转发的 URL，relay session 不存在。</td></tr><tr><td><strong>relay session</strong></td><td>一次 relay 传输的会话实例。</td></tr><tr><td><strong>relay session id</strong>（sid）</td><td>relay session 的唯一标识，用于路由到对应会话。</td></tr><tr><td><strong>delivery mode</strong></td><td>流媒体投递方式，取值：<code>direct</code>（直连）、<code>proxy</code>（透明代理）、<code>relay</code>（中转）。三者互斥。</td></tr><tr><td><strong>network source</strong></td><td>来源层面的概念，指来自远端网络的媒体，不决定最终采用哪种 delivery mode。同一 network source 可能走 direct、proxy 或 relay，视网络条件而定。</td></tr></tbody></table><hr><h2 id="_2-废弃术语" tabindex="-1">2. 废弃术语 <a class="header-anchor" href="#_2-废弃术语" aria-label="Permalink to &quot;2. 废弃术语&quot;">​</a></h2><p><strong><code>network_audio</code></strong> 为废弃术语（deprecated term）。</p><ul><li>本文档生效后（v1.0.9），不得在新增代码、文档、日志、路由命名中正式使用 <code>network_audio</code>。</li><li>兼容层若暂时保留旧名，必须标记为 <code>legacy alias</code>，不得扩散到主实现。</li></ul><hr><h2 id="_3-约束原则" tabindex="-1">3. 约束原则 <a class="header-anchor" href="#_3-约束原则" aria-label="Permalink to &quot;3. 约束原则&quot;">​</a></h2><ol><li><strong>命名边界</strong>：relay 语义统一使用 <code>relay</code>/<code>Relay</code> 前缀，不使用 <code>network_audio</code>。</li><li><strong>会话标识</strong>：relay session 的标识统一为 <code>sid</code>，不在其他语境中与 <code>session_id</code> 混用。</li><li><strong>文档要求</strong>：所有新增文档、日志、注释必须使用正式术语。</li></ol>',12)]))}const u=t(d,[["render",s]]);export{g as __pageData,u as default};
